import{_ as t,c as a,o as n,a5 as o}from"./chunks/framework.CgT1UzWm.js";const m=JSON.parse('{"title":"TAGS Annotation","titleTemplate":"NpgsqlRest","description":"Apply annotations conditionally based on routine volatility tags.","frontmatter":{"outline":[2,3],"title":"TAGS Annotation","titleTemplate":"NpgsqlRest","description":"Apply annotations conditionally based on routine volatility tags.","head":[["meta",{"name":"keywords","content":"npgsqlrest tags, conditional annotations, for keyword, volatility scoping"}],["meta",{"property":"og:title","content":"NpgsqlRest TAGS Annotation"}],["meta",{"property":"og:description","content":"Apply annotations conditionally based on routine volatility tags."}],["meta",{"property":"og:type","content":"article"}],["link",{"rel":"canonical","href":"https://npgsqlrest.github.io/annotations/tags.html"}],["meta",{"property":"og:url","content":"https://npgsqlrest.github.io/annotations/tags.html"}],["meta",{"property":"og:image","content":"https://npgsqlrest.github.io/og-image.png"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"NpgsqlRest TAGS Annotation"}],["meta",{"name":"twitter:description","content":"Apply annotations conditionally based on routine volatility tags."}],["meta",{"name":"twitter:image","content":"https://npgsqlrest.github.io/og-image.png"}]]},"headers":[],"relativePath":"annotations/tags.md","filePath":"annotations/tags.md","lastUpdated":1777620331000}'),s={name:"annotations/tags.md"};function i(l,e,c,d,r,p){return n(),a("div",null,e[0]||(e[0]=[o(`<h1 id="tags" tabindex="-1">TAGS <a class="header-anchor" href="#tags" aria-label="Permalink to &quot;TAGS&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">Also known as</p><p><code>for</code>, <code>tags</code>, <code>tag</code> (no <code>@</code> prefix needed; <code>@for</code> and <code>@tags</code> also work)</p></div><p>Apply subsequent annotations only when the routine matches a specific volatility or routine-type tag.</p><div class="tip custom-block"><p class="custom-block-title">Rarely needed</p><p>Most projects never use this. Reach for it only when a single comment needs to behave differently depending on the function&#39;s volatility — and even then, putting the annotations directly on the specific function is usually clearer.</p></div><h2 id="available-tags" tabindex="-1">Available tags <a class="header-anchor" href="#available-tags" aria-label="Permalink to &quot;Available tags&quot;">​</a></h2><p><code>RoutineSource</code> assigns these auto-tags to each function or procedure:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Tag</th><th>Matches</th></tr></thead><tbody><tr><td><code>function</code></td><td>PostgreSQL functions</td></tr><tr><td><code>procedure</code></td><td>PostgreSQL procedures</td></tr><tr><td><code>volatile</code></td><td>Functions declared <code>VOLATILE</code> (default)</td></tr><tr><td><code>stable</code></td><td>Functions declared <code>STABLE</code></td></tr><tr><td><code>immutable</code></td><td>Functions declared <code>IMMUTABLE</code></td></tr><tr><td><code>other</code></td><td>Procedures (volatility doesn&#39;t apply)</td></tr></tbody></table></div></div><p>That&#39;s the complete list. Custom tags are not supported, and SQL file endpoints have no auto-tags — <code>for</code> has no effect on them.</p><h2 id="syntax" tabindex="-1">Syntax <a class="header-anchor" href="#syntax" aria-label="Permalink to &quot;Syntax&quot;">​</a></h2><details class="code-collapsible" open><summary>code</summary><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>for &lt;tag1&gt;, &lt;tag2&gt;, ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><p>Annotations following a <code>for</code> line apply only when the routine matches at least one of the listed tags. The scope ends at the next <code>for</code> line or at the end of the comment.</p><h2 id="example-cache-only-when-immutable" tabindex="-1">Example: cache only when immutable <a class="header-anchor" href="#example-cache-only-when-immutable" aria-label="Permalink to &quot;Example: cache only when immutable&quot;">​</a></h2><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">comment on function calculate_hash(_data text) is </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">HTTP GET</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">for immutable</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">@cached&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></details><p>If the function is later changed to <code>STABLE</code> or <code>VOLATILE</code>, the <code>@cached</code> annotation no longer applies — no other comment changes needed. This is the one pattern where <code>for</code> carries its weight.</p><h2 id="behavior" tabindex="-1">Behavior <a class="header-anchor" href="#behavior" aria-label="Permalink to &quot;Behavior&quot;">​</a></h2><ul><li>Multiple <code>for</code> blocks can appear in the same comment; each scopes the annotations that follow it.</li><li>Tag matching is case-insensitive.</li><li>Comma- and space-separated lists are equivalent: <code>for stable, immutable</code> ≡ <code>for stable immutable</code>.</li><li>Annotations <em>before</em> any <code>for</code> line apply unconditionally.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./disabled.html">DISABLED</a> — hide an endpoint, optionally scoped by tag</li><li><a href="./enabled.html">ENABLED</a> — re-enable an endpoint, optionally scoped by tag</li></ul>`,18)]))}const u=t(s,[["render",i]]);export{m as __pageData,u as default};
